// ABOUTME: Injected into page context to set YouTube playback rate via the player API.
// ABOUTME: Bypasses YouTube's internal rate management that overrides direct video.playbackRate changes.
var searchParams = new URLSearchParams(document.currentScript.src.split('?')[1]);
var rate = parseFloat(searchParams.get('rate'));
if (rate && !isNaN(rate)) {
    var player = document.getElementById('movie_player');
    if (player && typeof player.setPlaybackRate === 'function') {
        player.setPlaybackRate(rate);
    }
}
